import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { WorkOrder } from '@/models/or';
import { User } from '@/models/user';
import { url } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'workOrders',
    template: () => import('./work-order-list.html?raw'),
    data: () => ({
        user: null as User | null,
        nav: null as string | null,
        aside: null as string | null,
        loading: true,

        totalWorkOrders: [] as WorkOrder[],
        workOrders: [] as WorkOrder[],

        // KPIs
        countTodayWorkOrders: -1,
        countYesterdayWorkOrders: 0,
        percentageSinceYesterday: -1,
        countTotalWorkOrders: -1,
        countPendingWorkOrders: -1,
        countClosedWorkOrders: -1,
        progressPercentage: 0,

        currentTab: 0,

        async init() {
            console.log('work-order-list@init');

            try {
                this.user = await getAuthenticatedUser();
            } catch (error) {
                location.href = '/login';
            }

            this.nav = await render(nav);
            this.aside = await render(aside);

            await this.loadWorkOrders();
        },

        async loadWorkOrders() {
            this.loading = true;

            try {
                if (this.$router.route === '/or/me') {
                    const mecs = await fetch(url(`/isiWeb/web/v1/empresas/01/mecanicos?usuario=${this.user.usuario}`), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                    });

                    const mecsResponse = await mecs.json();

                    const baseUrl = `/isiWeb/web/v1/empresas/01/ordenes-reparacion?mec=${mecsResponse.data[0].mec}`;
                    let fetchUrl = '';
                    switch (this.currentTab) {
                        case 0:
                            fetchUrl = baseUrl;
                            break;
                        case 1:
                            fetchUrl = `${baseUrl}&fecrep:eq=`;
                            break;
                        case 2:
                            fetchUrl = `${baseUrl}&fecrep:ne=`;
                            break;
                    }

                    const r = await fetch(url(fetchUrl), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                    });

                    const response = await r.json();

                    const workOrders = response.data as WorkOrder[];

                    this.workOrders = workOrders;
                }

                if (this.$router.route === '/or/list') {
                    const baseUrl = `/isiWeb/web/v1/empresas/01/ordenes-reparacion?almnro=${this.user.usuario}`;
                    let fetchUrl = '';
                    switch (this.currentTab) {
                        case 0:
                            fetchUrl = baseUrl;
                            break;
                        case 1:
                            fetchUrl = `${baseUrl}&fecrep:eq=`;
                            break;
                        case 2:
                            fetchUrl = `${baseUrl}&fecrep:ne=`;
                            break;
                    }
                    const r = await fetch(url(fetchUrl), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                    });

                    const response = await r.json();

                    const workOrders = response.data as WorkOrder[];

                    this.workOrders = workOrders;

                    if (this.currentTab === 0) {
                        this.totalWorkOrders = workOrders;
                    }

                    this.loadKpis();
                }
            } catch (error: any) {
                this.error = error.message;
            }

            this.loading = false;
        },

        loadKpis() {
            const today = new Date().toISOString().split('T')[0];

            const yesterdayDate = new Date();
            yesterdayDate.setDate(yesterdayDate.getDate() - 1);
            const yesterday = yesterdayDate.toISOString().split('T')[0];

            this.countTodayWorkOrders = this.totalWorkOrders.filter(
                (wo: WorkOrder) => wo.fecrep === null && wo.fedoc === today,
            ).length;
            this.countYesterdayWorkOrders = this.totalWorkOrders.filter(
                (wo: WorkOrder) => wo.fecrep === null && wo.fedoc === yesterday,
            ).length;
            this.percentageSinceYesterday =
                this.countYesterdayWorkOrders > 0
                    ? Math.round(
                          ((this.countTodayWorkOrders - this.countYesterdayWorkOrders) /
                              this.countYesterdayWorkOrders) *
                              100,
                      )
                    : 0;

            this.countTotalWorkOrders = this.totalWorkOrders.length;
            this.countPendingWorkOrders = this.totalWorkOrders.filter((wo: WorkOrder) => wo.fecrep === null).length;
            this.countClosedWorkOrders = this.totalWorkOrders.filter((wo: WorkOrder) => wo.fecrep !== null).length;

            this.progressPercentage =
                this.countTotalWorkOrders > 0
                    ? Math.round(
                          ((this.countTotalWorkOrders - this.countPendingWorkOrders) / this.countTotalWorkOrders) * 100,
                      )
                    : 0;
        },

        async changeTab() {
            await this.loadWorkOrders();
        },
    }),
} as ComponentModule;
